class Solution:
    def reverseOddLevels(self, root):
        # collect levels, reverse values on odd levels, rebuild
        from collections import deque
        levels = []
        q = deque([root]) if root else deque()
        while q:
            size = len(q)
            level = []
            for _ in range(size):
                node = q.popleft()
                level.append(node)
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
            levels.append(level)
        for d, level in enumerate(levels):
            if d % 2 == 1:
                vals = [n.val for n in level][::-1]
                for n, v in zip(level, vals):
                    n.val = v
        return root

