class Solution:
    def reverseOddLevels(self, root):
        level = [root] if root else []
        depth = 0
        while level and level[0] is not None:
            if depth % 2 == 1:
                i, j = 0, len(level) - 1
                while i < j:
                    level[i].val, level[j].val = level[j].val, level[i].val
                    i += 1
                    j -= 1
            nxt = []
            for node in level:
                if node.left:
                    nxt.append(node.left)
                if node.right:
                    nxt.append(node.right)
            level = nxt
            depth += 1
        return root

