var reverseOddLevels = function(root) {
    let level = root ? [root] : [];
    let depth = 0;
    while (level.length > 0) {
        if (depth % 2 === 1) {
            let i = 0, j = level.length - 1;
            while (i < j) {
                const t = level[i].val;
                level[i].val = level[j].val;
                level[j].val = t;
                i++; j--;
            }
        }
        const next = [];
        for (const node of level) {
            if (node.left) next.push(node.left);
            if (node.right) next.push(node.right);
        }
        level = next;
        depth++;
    }
    return root;
};
